const input = $input.first().json;
const payload = input.payload ?? input;
const action = payload.action ?? 'create_task';
const allowed = ['create_task', 'update_task', 'list_tasks', 'complete_task'];
if (!allowed.includes(action)) return [{ json: { status: 'error', task: {}, error: 'unsupported task action' } }];
if (action === 'create_task' && !payload.title) return [{ json: { status: 'error', task: {}, error: 'title is required' } }];
const task = { id: payload.id ?? `task_${Date.now()}`, title: payload.title ?? null, description: payload.description ?? null, assignee: payload.assignee ?? null, due_date: payload.due_date ?? null, priority: payload.priority ?? 'medium', status: action === 'complete_task' ? 'completed' : 'open' };
return [{ json: { status: 'success', task, sandbox: true, note: 'In production, connect this workflow to agent_tasks Postgres writes.' } }];
